# --- Helper: Extract public profile only ---

def to_public_profile(user_data):
    """Return only public fields from a user record."""
    if user_data is None:
        return None
    return {
        "id": user_data["id"],
        "username": user_data["username"],
        "bio": user_data.get("bio"),
    }


def get_current_user(context):
    """Safely retrieve the current authenticated user from context."""
    return context.get("current_user")


def get_current_user_id(context):
    """Safely retrieve the current authenticated user's ID from context."""
    user = get_current_user(context)
    if user:
        return user.get("id")
    return None


