query = QueryType()


@query.field("me")
def resolve_me(_, info):
    """
    Returns the full User (including private fields) for the authenticated user only.
    Requires authentication.
    """
    current_user = get_current_user(info.context)
    if current_user is None:
        raise Exception("Authentication required. Please provide a valid token.")
    # Return full user data only for the authenticated user themselves
    return current_user


@query.field("user")
def resolve_user(_, info, id):
    """
    Returns a public profile for any user by ID.
    Private fields are NOT exposed through this query (returns UserPublicProfile type).
    """
    # Validate and sanitize the id input
    user_id = str(id).strip()
    if not user_id.isalnum():
        raise Exception("Invalid user ID format.")

    user_data = USERS.get(user_id)
    if user_data is None:
        return None
    # Return only public profile data
    return to_public_profile(user_data)


@query.field("users")
def resolve_users(_, info):
    """
    Returns public profiles for all users.
    Private fields are NOT exposed (returns [UserPublicProfile] type).
    """
    return [to_public_profile(user) for user in USERS.values()]


@query.field("post")
def resolve_post(_, info, id):
    """
    Returns a post by ID. Unpublished posts are only visible to their author.
    """
    post_id = str(id).strip()
    if not post_id.isalnum():
        raise Exception("Invalid post ID format.")

    post = POSTS.get(post_id)
    if post is None:
        return None

    # If the post is not published, only the author can see it
    if not post.get("published", False):
        current_user_id = get_current_user_id(info.context)
        if current_user_id != post["author_id"]:
            return None  # Don't reveal existence of unpublished posts

    return post


@query.field("posts")
def resolve_posts(_, info):
    """
    Returns all published posts. Unpublished posts are excluded unless
    the authenticated user is the author.
    """
    current_user_id = get_current_user_id(info.context)
    result = []
    for post in POSTS.values():
        if post.get("published", False):
            result.append(post)
        elif current_user_id and current_user_id == post["author_id"]:
            # Author can see their own unpublished posts
            result.append(post)
    return result


