# --- Authentication Middleware ---

class AuthenticationMiddleware(BaseHTTPMiddleware):
    """
    Middleware that extracts the authentication token from the Authorization header
    and sets the current_user in the request state.
    """

    async def dispatch(self, request: Request, call_next):
        request.state.current_user = None

        auth_header = request.headers.get("Authorization", "")
        if auth_header.startswith("Bearer "):
            token = auth_header[7:].strip()
            # Validate token format (basic sanitization)
            if token and len(token) < 256:
                user_id = AUTH_TOKENS.get(token)
                if user_id:
                    user_data = USERS.get(user_id)
                    if user_data:
                        # Store a copy to prevent mutation
                        request.state.current_user = dict(user_data)

        response = await call_next(request)
        return response


# --- Custom GraphQL context ---

def get_context_value(request):
    """
    Build the GraphQL context from the request.
    The current_user is set by the authentication middleware.
    """
    current_user = getattr(request.state, "current_user", None) if hasattr(request, "state") else None
    return {
        "request": request,
        "current_user": current_user,
    }


# --- Query Depth / Complexity Limiting ---

MAX_QUERY_DEPTH = 5


def check_query_depth(document, max_depth=MAX_QUERY_DEPTH):
    """
    Simple query depth checker to prevent deeply nested queries
    that could cause performance issues.
    """
    from graphql import parse
    from graphql.language.ast import FieldNode, FragmentSpreadNode, InlineFragmentNode

    def measure_depth(node, current_depth=0):
        if current_depth > max_depth:
            return current_depth

        max_found = current_depth

        selections = getattr(node, 'selection_set', None)
        if selections:
            for selection in selections.selections:
                if isinstance(selection, (FieldNode, InlineFragmentNode)):
                    depth = measure_depth(selection, current_depth + 1)
                    max_found = max(max_found, depth)

        return max_found

    for definition in document.definitions:
        depth = measure_depth(definition)
        if depth > max_depth:
            raise Exception(
                f"Query depth {depth} exceeds maximum allowed depth of {max_depth}."
            )


